import{_ as e,c as a,o,a1 as r}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"クォータガバナンス: Quota Protection とウォームアップ | Antigravity-Manager","description":"Antigravity-Manager クォータガバナンスメカニズムを学びます。Quota Protection でモデルを閾値で保護し、Smart Warmup で自動的にウォームアップし、定期スキャンとクールダウン制御をサポートします。","frontmatter":{"title":"クォータガバナンス: Quota Protection とウォームアップ | Antigravity-Manager","subtitle":"クォータガバナンス: Quota Protection とウォームアップ | Antigravity-Manager","sidebarTitle":"モデルクォータを保護する","description":"Antigravity-Manager クォータガバナンスメカニズムを学びます。Quota Protection でモデルを閾値で保護し、Smart Warmup で自動的にウォームアップし、定期スキャンとクールダウン制御をサポートします。","tags":["quota","warmup","accounts","proxy"],"prerequisite":["start-add-account","start-proxy-and-first-client"],"order":5},"headers":[],"relativePath":"ja/lbjlaq/Antigravity-Manager/advanced/quota/index.md","filePath":"ja/lbjlaq/Antigravity-Manager/advanced/quota/index.md"}'),d={name:"ja/lbjlaq/Antigravity-Manager/advanced/quota/index.md"};function c(n,t,i,l,s,u){return o(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="クォータガバナンス-quota-protection-smart-warmup-の組み合わせ戦術" tabindex="-1">クォータガバナンス：Quota Protection + Smart Warmup の組み合わせ戦術 <a class="header-anchor" href="#クォータガバナンス-quota-protection-smart-warmup-の組み合わせ戦術" aria-label="Permalink to &quot;クォータガバナンス：Quota Protection + Smart Warmup の組み合わせ戦術&quot;">​</a></h1><p>Antigravity Tools でプロキシを動かしていると、最も怖いのは 1 つのこと：主力モデルのクォータが「こっそり使い尽くされ」、本当に使いたい時に低すぎて打てないと気づくことです。</p><p>このレッスンは <strong>クォータガバナンス</strong> に特化します：Quota Protection で重要なモデルを残し；Smart Warmup でクォータが回復した時に「軽量ウォームアップ」を行い、一時的な脱落を減らします。</p><h2 id="クォータガバナンスとは" tabindex="-1">クォータガバナンスとは？ <a class="header-anchor" href="#クォータガバナンスとは" aria-label="Permalink to &quot;クォータガバナンスとは？&quot;">​</a></h2><p><strong>クォータガバナンス</strong>とは、Antigravity Tools で 2 セットの連動メカニズムを使って「クォータをどう使うか」を制御することです：あるモデルの残りクォータが閾値以下になった場合、Quota Protection はそのモデルをアカウントの <code>protected_models</code> に加え、そのモデルをリクエストする際、優先的に回避します；クォータが 100% に戻ると、Smart Warmup が極小トラフィックのウォームアップリクエストをトリガーし、ローカル履歴ファイルで 4 時間のクールダウンを行います。</p><h2 id="このレッスンでできること" tabindex="-1">このレッスンでできること <a class="header-anchor" href="#このレッスンでできること" aria-label="Permalink to &quot;このレッスンでできること&quot;">​</a></h2><ul><li>Quota Protection を有効にし、低クォータアカウントが自動的に「譲歩」させ、高価値モデルを重要なリクエストのために残す</li><li>Smart Warmup を有効にし、クォータ回復後に自動的にウォームアップし（4 時間クールダウンがトリガー頻度にどう影響するかを理解）</li><li><code>quota_protection</code> / <code>scheduled_warmup</code> / <code>protected_models</code> の 3 つのフィールドがどこで有効になるかを明確にする</li><li>どのモデル名が「保護グループ」に正規化されるか（およびどのモデルがされないか）を知る</li></ul><h2 id="現在の悩み" tabindex="-1">現在の悩み <a class="header-anchor" href="#現在の悩み" aria-label="Permalink to &quot;現在の悩み&quot;">​</a></h2><ul><li>「アカウントをローテーションしている」と思っているが、実際はずっと同じ種類の高価値モデルを消費している</li><li>クォータが低くなって初めて気づく、さらに Claude Code/クライアントがバックグラウンドで warmup してクォータを食い尽くしている</li><li>ウォームアップを有効にしたが、いつトリガーされるか、クールダウンがあるか、クォータに影響するかがわからない</li></ul><h2 id="この方法をいつ使うか" tabindex="-1">この方法をいつ使うか <a class="header-anchor" href="#この方法をいつ使うか" aria-label="Permalink to &quot;この方法をいつ使うか&quot;">​</a></h2><ul><li>複数のアカウントプールがあり、「重要な瞬間」に重要モデルの余力を残したい</li><li>クォータ回復時間を手動で監視したくなく、システムに「回復後の軽量検証」を自動させたい</li></ul><h2 id="🎒-始める前の準備" tabindex="-1">🎒 始める前の準備 <a class="header-anchor" href="#🎒-始める前の準備" aria-label="Permalink to &quot;🎒 始める前の準備&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">前提条件</p><p>このレッスンは、既に以下ができることを前提としています：</p><ul><li><strong>Accounts</strong> ページでアカウントリストを見て、手動でクォータを更新できる</li><li>ローカルリバースプロキシを少なくとも 1 回起動できる（少なくとも <code>/healthz</code> にアクセス可能）</li></ul><p>まだ動かない場合は、まず <strong><a href="/docs/opencodedocs/ja/lbjlaq/Antigravity-Manager/start/proxy-and-first-client/">ローカルリバースプロキシを起動して最初のクライアントを接続する</a></strong> を見てください。</p></div><p>また、Smart Warmup はローカル履歴ファイル <code>warmup_history.json</code> を書き込みます。これはデータディレクトリにあり、データディレクトリの位置とバックアップ方法は先に <strong><a href="/docs/opencodedocs/ja/lbjlaq/Antigravity-Manager/start/first-run-data/">初回起動時の必知事項：データディレクトリ、ログ、トレイ、自動起動</a></strong> を見てください。</p><h2 id="コアコンセプト" tabindex="-1">コアコンセプト <a class="header-anchor" href="#コアコンセプト" aria-label="Permalink to &quot;コアコンセプト&quot;">​</a></h2><p>この「組み合わせ戦術」の背後は実は非常にシンプルです：</p><ul><li>Quota Protection は「もう無駄遣い」を担当：あるモデルが閾値以下になったら、保護済みモデルとしてマークし、そのモデルをリクエストする際、優先的に回避（モデルレベルで、アカウント全体を無条件に無効化しない）。</li><li>Smart Warmup は「回復したら検証」を担当：モデルが 100% に戻ると、軽量リクエストを 1 回トリガーし、リンクが利用可能かを確認し、4 時間のクールダウンで繰り返し邪魔されないようにする。</li></ul><p>これらに対応する設定フィールドはすべてフロントエンドの <code>AppConfig</code> にあります：</p><ul><li><code>quota_protection.enabled / threshold_percentage / monitored_models</code>（<code>src/types/config.ts</code> 参照）</li><li><code>scheduled_warmup.enabled / monitored_models</code>（<code>src/types/config.ts</code> 参照）</li></ul><p>そして実際に「そのモデルをリクエストする際、このアカウントをスキップするか」を決定するロジックはバックエンドの TokenManager にあります：</p><ul><li>アカウントファイルの <code>protected_models</code> は <code>get_token(..., target_model)</code> でフィルタリングに参加（<code>src-tauri/src/proxy/token_manager.rs</code> 参照）</li><li><code>target_model</code> はまず 1 回正規化（<code>normalize_to_standard_id</code>）されるため、<code>claude-sonnet-4-5-thinking</code> などの変体は同じ「保護グループ」に折り畳まれる（<code>src-tauri/src/proxy/common/model_mapping.rs</code> 参照）</li></ul><h2 id="次のレッスン予告" tabindex="-1">次のレッスン予告 <a class="header-anchor" href="#次のレッスン予告" aria-label="Permalink to &quot;次のレッスン予告&quot;">​</a></h2><blockquote><p>次のレッスンでは <strong><a href="/docs/opencodedocs/ja/lbjlaq/Antigravity-Manager/advanced/monitoring/">Proxy Monitor：リクエストログ、フィルタリング、詳細復元とエクスポート</a></strong> を学び、呼び出しブラックボックスを再現可能な証拠チェーンにします。</p></blockquote><h2 id="さあ、一緒にやってみよう" tabindex="-1">さあ、一緒にやってみよう <a class="header-anchor" href="#さあ、一緒にやってみよう" aria-label="Permalink to &quot;さあ、一緒にやってみよう&quot;">​</a></h2><h3 id="ステップ-1-まずクォータを「把握できる」まで更新" tabindex="-1">ステップ 1：まずクォータを「把握できる」まで更新 <a class="header-anchor" href="#ステップ-1-まずクォータを「把握できる」まで更新" aria-label="Permalink to &quot;ステップ 1：まずクォータを「把握できる」まで更新&quot;">​</a></h3><p><strong>なぜ</strong> Quota Protection はアカウントの <code>quota.models[].percentage</code> に基づいて判断します。あなたのクォータが更新されていないと、保護ロジックは何もできません。</p><p>操作パス：<strong>Accounts</strong> ページを開き、ツールバーの更新ボタンをクリック（単一アカウントまたは全量どちらでも可）。</p><p><strong>期待される結果</strong>：アカウント行に各モデルのクォータパーセンテージ（例：0-100）と reset time が表示される。</p><h3 id="ステップ-2-settings-で-smart-warmup-を開く-オプションだが推奨" tabindex="-1">ステップ 2：Settings で Smart Warmup を開く（オプションだが推奨） <a class="header-anchor" href="#ステップ-2-settings-で-smart-warmup-を開く-オプションだが推奨" aria-label="Permalink to &quot;ステップ 2：Settings で Smart Warmup を開く（オプションだが推奨）&quot;">​</a></h3><p><strong>なぜ</strong> Smart Warmup の目標は「クォータを節約」ではなく「クォータが回復したらリンクを自己検証」です。モデルクォータが 100% になった時のみトリガーされ、さらに 4 時間のクールダウンがあります。</p><p>操作パス：<strong>Settings</strong> を開き、アカウント関連設定エリアに切り替え、<strong>Smart Warmup</strong> スイッチを有効にし、監視したいモデルにチェックを入れる。</p><p>設定を保存するのを忘れないでください。</p><p><strong>期待される結果</strong>：Smart Warmup が展開され、モデルリストが表示される；少なくとも 1 つのモデルがチェックされている。</p><h3 id="ステップ-3-quota-protection-を開き、閾値と監視モデルを設定" tabindex="-1">ステップ 3：Quota Protection を開き、閾値と監視モデルを設定 <a class="header-anchor" href="#ステップ-3-quota-protection-を開き、閾値と監視モデルを設定" aria-label="Permalink to &quot;ステップ 3：Quota Protection を開き、閾値と監視モデルを設定&quot;">​</a></h3><p><strong>なぜ</strong> Quota Protection は「余力を残す」コアです：監視モデルのクォータパーセンテージ <code>&lt;= threshold_percentage</code> の場合、そのモデルをアカウントファイルの <code>protected_models</code> に書き込み、その後そのモデルをリクエストする際、この種のアカウントを優先的に回避します。</p><p>操作パス：<strong>Settings</strong> で <strong>Quota Protection</strong> を開く。</p><ol><li>閾値を設定（<code>1-99</code>）</li><li>監視したいモデルにチェックを入れる（少なくとも 1 つ）</li></ol><div class="tip custom-block"><p class="custom-block-title">非常に便利な初期設定</p><p>迷う場合、デフォルト <code>threshold_percentage=10</code> から始めればよい（<code>src/pages/Settings.tsx</code> 参照）。</p></div><p><strong>期待される結果</strong>：Quota Protection のモデルチェックで少なくとも 1 つが残っている（UI は最後の 1 つをキャンセルすることを阻止します）。</p><h3 id="ステップ-4-「保護グループ正規化」があなたをハマらせないことを確認" tabindex="-1">ステップ 4：「保護グループ正規化」があなたをハマらせないことを確認 <a class="header-anchor" href="#ステップ-4-「保護グループ正規化」があなたをハマらせないことを確認" aria-label="Permalink to &quot;ステップ 4：「保護グループ正規化」があなたをハマらせないことを確認&quot;">​</a></h3><p><strong>なぜ</strong> TokenManager がクォータ保護判断を行う際、まず <code>target_model</code> を標準 ID（<code>normalize_to_standard_id</code>）に正規化します。例：<code>claude-sonnet-4-5-thinking</code> は <code>claude-sonnet-4-5</code> に正規化されます。</p><p>これは以下を意味します：</p><ul><li>Quota Protection で <code>claude-sonnet-4-5</code> をチェックする</li><li>実際に <code>claude-sonnet-4-5-thinking</code> をリクエストする</li></ul><p>それでも保護がマッチする（同じグループに属するため）。</p><p><strong>期待される結果</strong>：あるアカウントの <code>protected_models</code> に <code>claude-sonnet-4-5</code> が含まれている場合、<code>claude-sonnet-4-5-thinking</code> へのリクエストはそのアカウントを優先的に回避する。</p><h3 id="ステップ-5-すぐに検証したい場合、「手動ウォームアップ」で-1-回-warmup-をトリガー" tabindex="-1">ステップ 5：すぐに検証したい場合、「手動ウォームアップ」で 1 回 warmup をトリガー <a class="header-anchor" href="#ステップ-5-すぐに検証したい場合、「手動ウォームアップ」で-1-回-warmup-をトリガー" aria-label="Permalink to &quot;ステップ 5：すぐに検証したい場合、「手動ウォームアップ」で 1 回 warmup をトリガー&quot;">​</a></h3><p><strong>なぜ</strong> 定期 Smart Warmup のスキャンサイクルは 10 分に 1 回（<code>src-tauri/src/modules/scheduler.rs</code> 参照）。すぐにリンクを検証したい場合、手動ウォームアップの方が直接的。</p><p>操作パス：<strong>Accounts</strong> ページを開き、ツールバーの「ウォームアップ」ボタンをクリック：</p><ul><li>アカウントを選択しない：全量ウォームアップをトリガー（<code>warm_up_all_accounts</code> 呼び出し）</li><li>アカウントを選択：選択したアカウントに 1 つずつウォームアップをトリガー（<code>warm_up_account</code> 呼び出し）</li></ul><p><strong>期待される結果</strong>：トーストが表示され、内容はバックエンドが返した文字列（例：&quot;Warmup task triggered ...&quot;）に由来する。</p><h2 id="チェックポイント-✅" tabindex="-1">チェックポイント ✅ <a class="header-anchor" href="#チェックポイント-✅" aria-label="Permalink to &quot;チェックポイント ✅&quot;">​</a></h2><ul><li>Accounts ページで各アカウントのモデルクォータパーセンテージが見える（クォータデータリンクが OK の証拠）</li><li>Settings で Quota Protection / Smart Warmup を開き、設定を正常に保存できる</li><li><code>protected_models</code> が「モデルレベル」制限であることを理解：1 つのアカウントが一部のモデルに対してのみ回避される可能性がある</li><li>warmup には 4 時間のクールダウンがあることを知っている：短時間で繰り返しウォームアップをクリックすると、「skipped/cooldown」関連のプロンプトが見える可能性がある</li></ul><h2 id="よくある落とし穴" tabindex="-1">よくある落とし穴 <a class="header-anchor" href="#よくある落とし穴" aria-label="Permalink to &quot;よくある落とし穴&quot;">​</a></h2><h3 id="_1-quota-protection-を有効にしたが、ずっと有効にならない" tabindex="-1">1) Quota Protection を有効にしたが、ずっと有効にならない <a class="header-anchor" href="#_1-quota-protection-を有効にしたが、ずっと有効にならない" aria-label="Permalink to &quot;1) Quota Protection を有効にしたが、ずっと有効にならない&quot;">​</a></h3><p>最も一般的な原因：アカウントに <code>quota</code> データがない。保護ロジックはバックエンドでまず <code>quota.models[]</code> を読み取る必要があるため、閾値を判断（<code>src-tauri/src/proxy/token_manager.rs</code> 参照）。</p><p><strong>ステップ 1</strong> に戻り、まずクォータを更新してください。</p><h3 id="_2-なぜ少数のモデルしか「保護グループ」として扱われないのか" tabindex="-1">2) なぜ少数のモデルしか「保護グループ」として扱われないのか？ <a class="header-anchor" href="#_2-なぜ少数のモデルしか「保護グループ」として扱われないのか" aria-label="Permalink to &quot;2) なぜ少数のモデルしか「保護グループ」として扱われないのか？&quot;">​</a></h3><p>TokenManager の <code>target_model</code> 正規化は「ホワイトリスト式」です：明確に列挙されたモデル名のみが標準 ID にマッピングされます（<code>src-tauri/src/proxy/common/model_mapping.rs</code> 参照）。</p><p>正規化後のロジックは：正規化後の名称（標準 ID または元のモデル名）を使ってアカウントの <code>protected_models</code> フィールドにマッチします。マッチ成功した場合、そのアカウントはスキップされます（<code>src-tauri/src/proxy/token_manager.rs:555-560, 716-719</code> 参照）。これは以下を意味します：</p><ul><li>ホワイトリスト内のモデル（例：<code>claude-sonnet-4-5-thinking</code>）は標準 ID（<code>claude-sonnet-4-5</code>）に正規化され、その後 <code>protected_models</code> に含まれるかを判断</li><li>ホワイトリスト外のモデル正規化失敗時、元のモデル名にフォールバックし、依然として <code>protected_models</code> にマッチする</li></ul><p>つまり、クォータ保護判断は「すべてのモデル名」に有効ですが、ホワイトリスト内のモデルはまず正規化されます。</p><h3 id="_3-手動-定期ウォームアップはなぜプロキシが実行されている必要があるのか" tabindex="-1">3) 手動/定期ウォームアップはなぜプロキシが実行されている必要があるのか？ <a class="header-anchor" href="#_3-手動-定期ウォームアップはなぜプロキシが実行されている必要があるのか" aria-label="Permalink to &quot;3) 手動/定期ウォームアップはなぜプロキシが実行されている必要があるのか？&quot;">​</a></h3><p>ウォームアップリクエストは最終的にローカルプロキシの内部エンドポイントに打ち込みます：<code>POST /internal/warmup</code>（<code>src-tauri/src/proxy/server.rs</code> のルート、および <code>src-tauri/src/proxy/handlers/warmup.rs</code> の実装を参照）。プロキシサービスを起動しない場合、warmup は失敗します。</p><p>また、ウォームアップ呼び出しのポートは設定から来ます：<code>proxy.port</code>（設定読み取り失敗時、<code>8045</code> にフォールバック、<code>src-tauri/src/modules/quota.rs</code> 参照）。</p><h2 id="このレッスンのまとめ" tabindex="-1">このレッスンのまとめ <a class="header-anchor" href="#このレッスンのまとめ" aria-label="Permalink to &quot;このレッスンのまとめ&quot;">​</a></h2><ul><li>Quota Protection は「損切り」：閾値以下になるとモデルを <code>protected_models</code> に書き込み、そのモデルをリクエストする際、優先的に回避</li><li>Smart Warmup は「回復自己検査」：100% 時のみトリガー、10 分に 1 回スキャン、4 時間クールダウン</li><li>両方とも「クォータ更新」リンクに依存：まず <code>quota.models[]</code> があってこそ、ガバナンスの基礎がある</li></ul><h2 id="次のレッスン予告-1" tabindex="-1">次のレッスン予告 <a class="header-anchor" href="#次のレッスン予告-1" aria-label="Permalink to &quot;次のレッスン予告&quot;">​</a></h2><p>クォータガバナンスが解決するのは「どうより安定して使うか」。次のレッスンでは Proxy Monitor を続けて見ることを推奨し、リクエストログ、アカウントマッチ、モデルマッピングをすべて再生可能な証拠チェーンにします。</p><hr><h2 id="付録-ソースコード参考" tabindex="-1">付録：ソースコード参考 <a class="header-anchor" href="#付録-ソースコード参考" aria-label="Permalink to &quot;付録：ソースコード参考&quot;">​</a></h2><details><summary><strong>クリックしてソースコードの位置を展開</strong></summary><blockquote><p>更新日時：2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>機能</th><th>ファイルパス</th><th>行番号</th></tr></thead><tbody><tr><td>Quota Protection UI（閾値、モデルチェック、少なくとも 1 つ残す）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/settings/QuotaProtection.tsx#L13-L168" target="_blank" rel="noreferrer"><code>src/components/settings/QuotaProtection.tsx</code></a></td><td>13-168</td></tr><tr><td>Smart Warmup UI（有効化後デフォルトチェック、少なくとも 1 つ残す）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/settings/SmartWarmup.tsx#L14-L120" target="_blank" rel="noreferrer"><code>src/components/settings/SmartWarmup.tsx</code></a></td><td>14-120</td></tr><tr><td>クォータガバナンス設定フィールド（<code>quota_protection</code> / <code>scheduled_warmup</code>）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/types/config.ts#L54-L94" target="_blank" rel="noreferrer"><code>src/types/config.ts</code></a></td><td>54-94</td></tr><tr><td>デフォルト閾値とデフォルト設定（<code>threshold_percentage: 10</code>）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Settings.tsx#L20-L51" target="_blank" rel="noreferrer"><code>src/pages/Settings.tsx</code></a></td><td>20-51</td></tr><tr><td><code>protected_models</code> 書き込み/復元（閾値判断と永続化）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L254-L467" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>254-467</td></tr><tr><td>リクエスト側クォータ保護フィルタリング（<code>get_token(..., target_model)</code>）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L470-L674" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>470-674</td></tr><tr><td>保護グループ正規化（<code>normalize_to_standard_id</code>）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/common/model_mapping.rs#L230-L254" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/common/model_mapping.rs</code></a></td><td>230-254</td></tr><tr><td>Smart Warmup 定期スキャン（10 分に 1 回 + 4 時間クールダウン + <code>warmup_history.json</code>）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/scheduler.rs#L11-L221" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/scheduler.rs</code></a></td><td>11-221</td></tr><tr><td>手動ウォームアップコマンド（<code>warm_up_all_accounts</code> / <code>warm_up_account</code>）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L167-L212" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>167-212</td></tr><tr><td>ウォームアップ実装（内部エンドポイント <code>/internal/warmup</code> 呼び出し）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/quota.rs#L271-L512" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/quota.rs</code></a></td><td>271-512</td></tr><tr><td>内部ウォームアップエンドポイント実装（リクエスト構築 + アップストリーム呼び出し）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/warmup.rs#L3-L220" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/warmup.rs</code></a></td><td>3-220</td></tr></tbody></table></details>',71)])])}const h=e(d,[["render",c]]);export{m as __pageData,h as default};
